// Selectionner Photo Contexte — cd17b
const slot = $('Charger Direction Artistique').first().json;
const contextAssets = $('Charger Images Contexte').all();
const fileData = $('Identifier Nouveau Fichier').first().json;

const compositingContext = slot.compositing_context;

if (!compositingContext || compositingContext.trim() === '') {
  return [{
    json: {
      hasCompositing: false,
      contextAssetUrl: null,
      contextAssetDescription: null,
      slot_id: fileData.slot_id,
      client_id: fileData.client_id,
      client_slug: fileData.client_slug,
      fileName: fileData.fileName
    }
  }];
}

const keywords = compositingContext.toLowerCase().split(/[\s,\u2014\-]+/).filter(k => k.length > 2);
let bestMatch = null;
let bestScore = 0;

for (const asset of contextAssets) {
  const a = asset.json;
  if (!a || !a.file_url) continue;

  const m = typeof a.metadata === 'string' ? JSON.parse(a.metadata) : (a.metadata || {});
  const description = (m.description || '').toLowerCase();
  const tags = (m.tags || []).map(t => t.toLowerCase());
  const name = (a.name || '').toLowerCase();

  let score = 0;
  for (const kw of keywords) {
    if (description.includes(kw)) score += 2;
    if (tags.some(t => t.includes(kw))) score += 3;
    if (name.includes(kw)) score += 1;
  }

  if (score > bestScore) {
    bestScore = score;
    bestMatch = { url: a.file_url, description: m.description || a.name, tags: m.tags || [] };
  }
}

if (!bestMatch || bestScore === 0) {
  return [{
    json: {
      hasCompositing: false,
      contextAssetUrl: null,
      contextAssetDescription: null,
      _warning: 'compositing_context rempli mais aucune photo ne correspond: ' + compositingContext,
      slot_id: fileData.slot_id,
      client_id: fileData.client_id,
      client_slug: fileData.client_slug,
      fileName: fileData.fileName
    }
  }];
}

return [{
  json: {
    hasCompositing: true,
    contextAssetUrl: bestMatch.url,
    contextAssetDescription: bestMatch.description,
    contextAssetTags: bestMatch.tags,
    compositingContext: compositingContext,
    slot_id: fileData.slot_id,
    client_id: fileData.client_id,
    client_slug: fileData.client_slug,
    fileName: fileData.fileName
  }
}];

