          },
          { type: 'image_url', image_url: { url: 'data:' + mimeType1 + ';base64,' + imgBrute.data } },
          { type: 'image_url', image_url: { url: 'data:' + mimeType2 + ';base64,' + imgContexte.data } }
        ]
      }]
    },
    json: true
  });

  const content = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '';
  let result;
  try {
    result = JSON.parse(content);
  } catch (e) {
    const match = content.match(/\{[\s\S]*\}/);
    if (match) { try { result = JSON.parse(match[0]); } catch (e2) { /* ignore */ } }
  }

  if (result && result.feasible === false) {
    return [{ json: {
      ...compData,
      hasCompositing: false,
      _compositingRejected: true,
      _rejectReason: result.reason || 'Compositing juge incoherent par le garde-fou vision'
    }, binary }];
  }

  // Compositing valide
  return [{ json: { ...compData, _compositingValidated: true }, binary }];

