  } catch (e) {
    const match = content.match(/\{[\s\S]*\}/);
    if (match) { try { result = JSON.parse(match[0]); } catch (e2) { /* ignore */ } }
  }

  if (result && result.feasible === false) {
    return [{ json: {
      ...compData,
      hasCompositing: false,
      _compositingRejected: true,
      _rejectReason: result.reason || 'Compositing juge incoherent par le garde-fou vision'
    }, binary }];
  }

  // Compositing valide
  return [{ json: { ...compData, _compositingValidated: true }, binary }];

} catch (e) {
