// Valider Sortie Caption — cd24b
// Pattern aligne avec WF03 "Valider Sortie Story" (cd15a)
const raw = $('Agent Redacteur').first().json.output || $('Agent Redacteur').first().json.text || '';
const slot = $('Charger Direction Artistique').first().json;
const contentType = slot.content_type || 'post';

// Parsing JSON robuste (meme pattern que WF01/WF03)
let parsed;
try {
  parsed = typeof raw === 'object' ? raw : JSON.parse(raw);
} catch (e) {
  const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try { parsed = JSON.parse(match[1].trim()); } catch (e2) {}
  }
  if (!parsed) {
    const braceMatch = raw.match(/\{[\s\S]*\}/);
    if (braceMatch) {
      try { parsed = JSON.parse(braceMatch[0]); } catch (e3) {}
    }
  }
}

if (!parsed || !parsed.caption) {
  throw new Error('Parsing caption echoue — output brut: ' + raw.substring(0, 200));
}

// Validation structure
if (!parsed.hashtags || !Array.isArray(parsed.hashtags)) {
  parsed.hashtags = [];
}
if (!parsed.cta) {
  parsed.cta = '';
}

// Nettoyage hashtags (retirer # si present)
parsed.hashtags = parsed.hashtags.map(h => h.replace(/^#/, ''));

// Validation longueur
const wordCount = parsed.caption.split(/\s+/).filter(Boolean).length;
if (contentType === 'post' && (wordCount < 50 || wordCount > 400)) {
  throw new Error(`Caption post: ${wordCount} mots (attendu 50-400)`);
}
if (contentType === 'story' && wordCount > 60) {
  throw new Error(`Caption story: ${wordCount} mots (attendu < 60)`);
}

// Validation formules bannies
const banned = ["n'hesitez pas", 'decouvrez notre', 'decouvrez nos'];
const captionLower = parsed.caption.toLowerCase();
for (const formula of banned) {
  if (captionLower.includes(formula)) {
    throw new Error(`Formule bannie detectee: \"${formula}\"`);
  }
}

return [{ json: {
  caption: parsed.caption,
  hashtags: parsed.hashtags,
  cta: parsed.cta,
  content_type: contentType,
  word_count: wordCount,
  validation: 'ok'
}}];

